import{c as s,Q as a,j as o,m as n}from"./chunks/framework.CBiVa4O3.js";const h=JSON.parse('{"title":"Skill 设计模式","description":"","frontmatter":{},"headers":[],"relativePath":"../claudeLearning/28-Skill设计模式.md","filePath":"../claudeLearning/28-Skill设计模式.md","lastUpdated":1778496697000}'),l={name:"../claudeLearning/28-Skill设计模式.md"};function e(r,t,i,p,d,g){return a(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="skill-设计模式" tabindex="-1">Skill 设计模式 <a class="header-anchor" href="#skill-设计模式" aria-label="Permalink to &quot;Skill 设计模式&quot;">​</a></h1><p>到这里五种&quot;扩展 Claude&quot;的方式你都见过了:<strong>Slash Command / Hook / Skill / Subagent / MCP</strong>。每一种都讲了&quot;是什么、怎么写&quot;。但生产里最常被问的不是&quot;它们各自怎么写&quot;,而是&quot;这件事我该用哪个&quot;。这一篇把所有&quot;选型决策&quot;集中讲清楚——<strong>这是 Claude 生态高阶玩家和入门玩家最大的差距</strong>。</p><blockquote><p>一句话先记住:<strong>按&quot;谁触发&quot;和&quot;在哪执行&quot;两个维度选</strong>。用户主动 = slash;生命周期事件 = hook;LLM 看场景自动 = skill;独立子任务 = subagent;外接系统 = MCP。</p></blockquote><hr><h2 id="一、五种扩展机制总图" tabindex="-1">一、五种扩展机制总图 <a class="header-anchor" href="#一、五种扩展机制总图" aria-label="Permalink to &quot;一、五种扩展机制总图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                         我要扩展 Claude 的某个能力</span></span>
<span class="line"><span>                                 │</span></span>
<span class="line"><span>            ┌────────────────────┼────────────────────┐</span></span>
<span class="line"><span>            ▼                    ▼                    ▼</span></span>
<span class="line"><span>       谁触发?              在哪执行?            连接外部?</span></span>
<span class="line"><span>            │                    │                    │</span></span>
<span class="line"><span>   ┌────────┼────────┐    ┌──────┴──────┐         ┌──┴──┐</span></span>
<span class="line"><span>   ▼        ▼        ▼    ▼             ▼         ▼     ▼</span></span>
<span class="line"><span>用户主动  系统自动  LLM自动  主对话上下文  独立 fork    系统 API</span></span>
<span class="line"><span>   │        │        │    │             │</span></span>
<span class="line"><span>   ▼        ▼        ▼    ▼             ▼</span></span>
<span class="line"><span> SLASH    HOOK    SKILL  (任意)       SUBAGENT</span></span>
<span class="line"><span>                   ↑                                  ▼</span></span>
<span class="line"><span>                   └─在主上下文加专业指令 / 资源   MCP server</span></span></code></pre></div><hr><h2 id="二、决策表-按需求类型选" tabindex="-1">二、决策表:按需求类型选 <a class="header-anchor" href="#二、决策表-按需求类型选" aria-label="Permalink to &quot;二、决策表:按需求类型选&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需求</th><th>该选</th><th>例子</th></tr></thead><tbody><tr><td>反复用同一段 prompt</td><td><strong>Slash</strong></td><td><code>/review</code>、<code>/translate</code></td></tr><tr><td>反复跑同一个流程(多步)</td><td><strong>Slash</strong></td><td><code>/deploy-staging</code></td></tr><tr><td>改文件后要做 X(每次)</td><td><strong>Hook PostToolUse</strong></td><td>改 .ts 后自动 prettier</td></tr><tr><td>提交 commit 前要 X</td><td><strong>Hook PreToolUse</strong></td><td>git commit 前跑测试</td></tr><tr><td>用户输 prompt 时要预处理</td><td><strong>Hook UserPromptSubmit</strong></td><td>注入当前分支信息</td></tr><tr><td>Claude 停下时要做 X</td><td><strong>Hook Stop</strong></td><td>自动 git status</td></tr><tr><td>看场景&quot;这个任务该按某流程做&quot;</td><td><strong>Skill</strong></td><td>&quot;审 PR&quot;、&quot;做安全审查&quot;、&quot;配 settings&quot;</td></tr><tr><td>让 LLM 看到 SQL 就按规范写</td><td><strong>Skill</strong></td><td>sql-expert</td></tr><tr><td>一段子任务,要独立 context 跑完</td><td><strong>Subagent</strong></td><td>大 monorepo 探索代码</td></tr><tr><td>多个并行调研</td><td><strong>Subagent</strong>(多个)</td><td>同时审 3 个维度</td></tr><tr><td>只读探索,不改文件</td><td><strong>Subagent</strong>(read-only)</td><td>Explore</td></tr><tr><td>接公司内部平台</td><td><strong>MCP server</strong></td><td>deploy / 监控 / 工单</td></tr><tr><td>接 SaaS(GitHub / Notion)</td><td><strong>MCP server</strong></td><td>github / notion 官方 server</td></tr><tr><td>让 LLM 操作业务 DB</td><td><strong>MCP server</strong></td><td>postgres</td></tr></tbody></table><hr><h2 id="三、容易混淆的几对" tabindex="-1">三、容易混淆的几对 <a class="header-anchor" href="#三、容易混淆的几对" aria-label="Permalink to &quot;三、容易混淆的几对&quot;">​</a></h2><h3 id="_3-1-slash-vs-hook" tabindex="-1">3.1 Slash vs Hook <a class="header-anchor" href="#_3-1-slash-vs-hook" aria-label="Permalink to &quot;3.1 Slash vs Hook&quot;">​</a></h3><p><strong>问题</strong>:都能&quot;跑一段 shell + 调一段 prompt&quot;,怎么选?</p><p><strong>答</strong>:</p><ul><li><strong>slash 是用户主动</strong>:你输 <code>/xxx</code> 才跑,<strong>不输不跑</strong></li><li><strong>hook 是事件触发</strong>:某条件成立<strong>一定跑</strong>,你不能跳过</li></ul><p><strong>选</strong>:</p><ul><li>你希望&quot;想跑就跑,不想跑就不跑&quot; → slash</li><li>你希望&quot;团队所有人每次都做这件事&quot; → hook</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;提交前希望跑测试&quot;</span></span>
<span class="line"><span> → 想强制 = hook</span></span>
<span class="line"><span> → 提示性 = slash(/test 跑测试,你自己决定要不要)</span></span></code></pre></div><h3 id="_3-2-skill-vs-slash" tabindex="-1">3.2 Skill vs Slash <a class="header-anchor" href="#_3-2-skill-vs-slash" aria-label="Permalink to &quot;3.2 Skill vs Slash&quot;">​</a></h3><p><strong>问题</strong>:都是&quot;prompt 模板&quot;,怎么选?</p><p><strong>答</strong>:</p><ul><li><strong>slash 是用户主动</strong>:输 <code>/review</code> 触发</li><li><strong>skill 是 LLM 自动</strong>:看到&quot;我开了个 PR&quot; 自动激活</li></ul><p><strong>选</strong>:</p><ul><li>我<strong>自己</strong>手动用 → slash</li><li>我希望 <strong>LLM 自己</strong>碰到合适场景就上 → skill</li></ul><blockquote><p>如果你希望&quot;LLM 自动审 PR&quot; + &quot;我也能手动 <code>/review</code>&quot;,两者都写——slash 触发主流程,skill 在 slash prompt 加专业指引,<strong>两者协作</strong>。</p></blockquote><h3 id="_3-3-skill-vs-subagent" tabindex="-1">3.3 Skill vs Subagent <a class="header-anchor" href="#_3-3-skill-vs-subagent" aria-label="Permalink to &quot;3.3 Skill vs Subagent&quot;">​</a></h3><p><strong>问题</strong>:都让 Claude 做&quot;专业领域任务&quot;,怎么选?</p><p><strong>答</strong>:</p><ul><li><strong>skill 在主上下文里加指令</strong>——Claude 仍然是同一个 session、同一个 context</li><li><strong>subagent 派出 fork</strong>——独立 session、独立 context、独立预算</li></ul><p><strong>选</strong>:</p><ul><li>任务和主流程交织、需要看到全局 → <strong>skill</strong>(让主 Claude 按某规范做)</li><li>任务可独立、读多写少、要省主 context → <strong>subagent</strong></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;审 PR&quot;:可独立 → subagent + skill 配合(skill 给指引,主 Claude 派 subagent 执行)</span></span>
<span class="line"><span>&quot;写 SQL&quot;:每次都按某规范 → skill</span></span>
<span class="line"><span>&quot;探索代码&quot;:独立 → subagent</span></span></code></pre></div><h3 id="_3-4-subagent-vs-mcp" tabindex="-1">3.4 Subagent vs MCP <a class="header-anchor" href="#_3-4-subagent-vs-mcp" aria-label="Permalink to &quot;3.4 Subagent vs MCP&quot;">​</a></h3><p><strong>问题</strong>:都让 Claude 多一份能力,怎么选?</p><p><strong>答</strong>:</p><ul><li><strong>subagent 是 Claude 自己再 fork 一个 Claude</strong>——能力本质是 LLM</li><li><strong>MCP 是接外部系统</strong>——能力本质是 API</li></ul><p><strong>选</strong>:</p><ul><li>任务靠 LLM 推理 → subagent</li><li>任务靠<strong>调用外部数据 / 系统</strong> → MCP</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;审 PR 里的安全风险&quot; → subagent(LLM 推理)</span></span>
<span class="line"><span>&quot;查 PR 当前的 CI 状态&quot; → MCP(调 GitHub API)</span></span></code></pre></div><h3 id="_3-5-hook-vs-mcp" tabindex="-1">3.5 Hook vs MCP <a class="header-anchor" href="#_3-5-hook-vs-mcp" aria-label="Permalink to &quot;3.5 Hook vs MCP&quot;">​</a></h3><p><strong>问题</strong>:都能跑代码,怎么选?</p><p><strong>答</strong>:</p><ul><li><strong>hook 是 Claude Code 自身的&quot;插件&quot;,不暴露给 LLM</strong>——不进 LLM 决策</li><li><strong>MCP server 暴露 tools,LLM 主动调</strong></li></ul><p><strong>选</strong>:</p><ul><li>我希望 LLM <strong>不知道</strong>这件事(后台自动) → hook</li><li>我希望 LLM <strong>会用到</strong>这件事 → MCP</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;改完 ts 文件自动 prettier&quot; → hook(LLM 不需要知道,后台跑)</span></span>
<span class="line"><span>&quot;在 GitHub 上创建 PR&quot; → MCP(LLM 决定何时创建)</span></span></code></pre></div><hr><h2 id="四、组合用法-一个真实需求拆解" tabindex="-1">四、组合用法:一个真实需求拆解 <a class="header-anchor" href="#四、组合用法-一个真实需求拆解" aria-label="Permalink to &quot;四、组合用法:一个真实需求拆解&quot;">​</a></h2><p>需求:<strong>&quot;团队希望每次写代码时按公司风格写,提交前自动跑测试,审 PR 时按公司清单查&quot;</strong></p><p>拆解:</p><table tabindex="0"><thead><tr><th>子需求</th><th>选哪个</th></tr></thead><tbody><tr><td>&quot;按公司风格写&quot;</td><td><strong>Skill</strong>(LLM 看到写代码场景就按规范来)</td></tr><tr><td>&quot;提交前自动跑测试&quot;</td><td><strong>Hook PreToolUse</strong>(git commit 拦截 → 跑测试)</td></tr><tr><td>&quot;审 PR&quot;</td><td><strong>Skill <code>pr-review</code></strong>(Claude 看到&quot;审 PR&quot; 触发) + 内部 <strong>Subagent</strong> 并行审多维度</td></tr><tr><td>&quot;PR 留 comment&quot;</td><td><strong>MCP github server</strong>(用现成的)</td></tr><tr><td>&quot;团队成员手动审 PR&quot;</td><td><strong>Slash <code>/review</code></strong>(辅助手动触发)</td></tr></tbody></table><p>最后:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/</span></span>
<span class="line"><span>  settings.json          # hook 配置:提交前跑测试</span></span>
<span class="line"><span>  skills/</span></span>
<span class="line"><span>    company-style/SKILL.md      # 公司风格 skill</span></span>
<span class="line"><span>    pr-review/SKILL.md          # PR 审查 skill</span></span>
<span class="line"><span>  agents/</span></span>
<span class="line"><span>    explore.md             # 只读探索 subagent</span></span>
<span class="line"><span>    security-auditor.md    # 安全审查 subagent</span></span>
<span class="line"><span>  commands/</span></span>
<span class="line"><span>    review.md              # /review slash</span></span>
<span class="line"><span>.mcp.json                  # GitHub MCP server</span></span></code></pre></div><p><strong>这五种机制叠加,一个完整 dev 工作流就成型了</strong>。任何一个机制单独都做不到全部——<strong>它们设计出来就是协作</strong>。</p><hr><h2 id="五、反模式-常见错配" tabindex="-1">五、反模式:常见错配 <a class="header-anchor" href="#五、反模式-常见错配" aria-label="Permalink to &quot;五、反模式:常见错配&quot;">​</a></h2><h3 id="_5-1-用-prompt-memory-写-每次都要" tabindex="-1">5.1 用 prompt / memory 写&quot;每次都要&quot; <a class="header-anchor" href="#_5-1-用-prompt-memory-写-每次都要" aria-label="Permalink to &quot;5.1 用 prompt / memory 写&quot;每次都要&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CLAUDE.md:</span></span>
<span class="line"><span>  - 每次提交前一定要跑测试</span></span>
<span class="line"><span>  - 每次写完代码一定要 lint</span></span></code></pre></div><p><strong>错</strong>——LLM 是概率系统,会忘 / 跳。<strong>确定性的事一律 hook</strong>。</p><h3 id="_5-2-把-知识-写成-hook" tabindex="-1">5.2 把&quot;知识&quot;写成 hook <a class="header-anchor" href="#_5-2-把-知识-写成-hook" aria-label="Permalink to &quot;5.2 把&quot;知识&quot;写成 hook&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hook PreToolUse(Bash) :</span></span>
<span class="line"><span>  if cmd starts with &quot;git commit&quot;:</span></span>
<span class="line"><span>    echo &quot;记得本项目用 conventional commits 风格&quot; &gt;&amp;2</span></span></code></pre></div><p><strong>错</strong>——这是知识,不是流程。<strong>写进 CLAUDE.md 或 skill</strong>,LLM 看到自然遵守。</p><h3 id="_5-3-用-slash-实现-llm-主动行为" tabindex="-1">5.3 用 slash 实现 LLM 主动行为 <a class="header-anchor" href="#_5-3-用-slash-实现-llm-主动行为" aria-label="Permalink to &quot;5.3 用 slash 实现 LLM 主动行为&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/auto-review (希望 LLM 写完代码自动调它)</span></span></code></pre></div><p><strong>错</strong>——slash 用户主动用;让 LLM 主动用应该写 <strong>skill</strong> 或在 system prompt 里告诉它。</p><h3 id="_5-4-用-subagent-做单步操作" tabindex="-1">5.4 用 subagent 做单步操作 <a class="header-anchor" href="#_5-4-用-subagent-做单步操作" aria-label="Permalink to &quot;5.4 用 subagent 做单步操作&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Task({prompt: &quot;把这个 typo 改了&quot;})</span></span></code></pre></div><p><strong>错</strong>——subagent 派 fork 有开销。<strong>主 Claude 一步搞定就行</strong>。</p><h3 id="_5-5-用-hook-做-llm-该做的事" tabindex="-1">5.5 用 hook 做 LLM 该做的事 <a class="header-anchor" href="#_5-5-用-hook-做-llm-该做的事" aria-label="Permalink to &quot;5.5 用 hook 做 LLM 该做的事&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hook PostToolUse: 自动判断要不要补测试</span></span></code></pre></div><p><strong>错</strong>——&quot;判断&quot;是 LLM 的活,hook 是确定性的。<strong>写进 skill 让 LLM 自己判断</strong>。</p><hr><h2 id="六、设计-review-一个能力该放哪一层" tabindex="-1">六、设计 review:一个能力该放哪一层? <a class="header-anchor" href="#六、设计-review-一个能力该放哪一层" aria-label="Permalink to &quot;六、设计 review:一个能力该放哪一层?&quot;">​</a></h2><p>每次设计前问自己:</p><ol><li><p><strong>这件事是确定性还是要 LLM 判断?</strong></p><ul><li>确定性 → hook(必跑)/ MCP(必能调)</li><li>要判断 → skill(LLM 自己上)/ subagent(LLM 派出去)</li></ul></li><li><p><strong>触发条件是什么?</strong></p><ul><li>用户主动 → slash</li><li>系统事件 → hook</li><li>LLM 看场景 → skill</li><li>LLM 派子任务 → subagent</li></ul></li><li><p><strong>是否需要外部 API?</strong></p><ul><li>要 → MCP</li><li>不要 → 其他四种</li></ul></li><li><p><strong>是否独立上下文?</strong></p><ul><li>要 → subagent</li><li>不要 → skill / hook / MCP / slash</li></ul></li></ol><hr><h2 id="七、组合-vs-单一-何时该混搭" tabindex="-1">七、组合 vs 单一:何时该混搭 <a class="header-anchor" href="#七、组合-vs-单一-何时该混搭" aria-label="Permalink to &quot;七、组合 vs 单一:何时该混搭&quot;">​</a></h2><p>很多功能不是&quot;选一个&quot;,是<strong>组合</strong>。规则:</p><ul><li><strong>slash + hook</strong>:slash 触发流程,流程内 hook 兜底</li><li><strong>skill + subagent</strong>:skill 给&quot;标准方法&quot;,方法里调 subagent 执行</li><li><strong>MCP + skill</strong>:MCP 提供工具,skill 教 LLM 何时怎么用这些工具</li><li><strong>hook + MCP</strong>:hook 拦危险 MCP 调用(如 deny <code>mcp__db__delete_*</code>)</li></ul><blockquote><p>单一机制能解决简单需求;<strong>复杂工作流几乎一定是组合</strong>。看你写的扩展全是 slash 或全是 hook,大概率是没用对工具。</p></blockquote><hr><h2 id="八、写新扩展前的-checklist" tabindex="-1">八、写新扩展前的 checklist <a class="header-anchor" href="#八、写新扩展前的-checklist" aria-label="Permalink to &quot;八、写新扩展前的 checklist&quot;">​</a></h2><p>新加一个&quot;让 Claude 干 X&quot;的能力前,过这些:</p><ul><li>[ ] 已有 skill / slash / MCP 能干吗?(避免重复)</li><li>[ ] 是确定性还是判断性?</li><li>[ ] 谁触发?</li><li>[ ] 在哪执行?</li><li>[ ] 有没有副作用?要不要 dry_run / confirm?</li><li>[ ] 出错怎么办?</li><li>[ ] 给团队还是个人?(决定层级)</li><li>[ ] 一句话能描述&quot;何时用我&quot;吗?(否则 description 写不好)</li></ul><hr><h2 id="九、复杂场景案例-数据分析-agent" tabindex="-1">九、复杂场景案例:数据分析 Agent <a class="header-anchor" href="#九、复杂场景案例-数据分析-agent" aria-label="Permalink to &quot;九、复杂场景案例:数据分析 Agent&quot;">​</a></h2><p>需求:<strong>业务分析师对话式问数据,Agent 能查、画、分析、积累常用查询</strong>。</p><p>设计:</p><table tabindex="0"><thead><tr><th>能力</th><th>选层</th><th>实现</th></tr></thead><tbody><tr><td>查 SQL</td><td>MCP <code>postgres-server</code></td><td>现成社区 server</td></tr><tr><td>画图</td><td>MCP <code>code-execution</code></td><td>Anthropic 自家 server</td></tr><tr><td>大数据集分析</td><td>Subagent</td><td>派一个 subagent 处理大查询</td></tr><tr><td>&quot;这个查询常用,封一下&quot;</td><td>Slash <code>/usage-by-region</code></td><td>把常用 query 封 slash</td></tr><tr><td>写 SQL 时按公司表命名规范</td><td>Skill <code>sql-style</code></td><td>LLM 看到写 SQL 就按规范</td></tr><tr><td>查询完自动写到分析报告</td><td>Hook Stop</td><td>自动 append 到 report.md</td></tr><tr><td>不允许 DROP / DELETE</td><td>Permissions deny</td><td>在 MCP tool 层面 + 主对话 deny</td></tr></tbody></table><p><strong>这一套组合下来 = 一个生产级数据分析 agent</strong>。任何一种机制单独干不了。</p><hr><h2 id="十、踩坑" tabindex="-1">十、踩坑 <a class="header-anchor" href="#十、踩坑" aria-label="Permalink to &quot;十、踩坑&quot;">​</a></h2><ol><li><strong>不知道有这五种,只用 slash</strong>——什么自动化都用 slash 模板硬扛</li><li><strong>不知道有 hook,把&quot;每次都要&quot;写进 prompt</strong>——LLM 偶尔忘</li><li><strong>不知道有 skill,反复输入&quot;按这套方法&quot;</strong>——LLM 该自动会的能力你手动喊</li><li><strong>不知道有 subagent,主 context 越积越多</strong></li><li><strong>不知道有 MCP,内部系统操作只能复制粘贴</strong></li><li><strong>同一件事用了两种实现</strong>(slash + skill 都有 review)——LLM 不知道用哪个</li><li><strong>skill 太多互相重叠</strong>——LLM 选哪个看心情;<strong>定期 audit / 合并</strong></li><li><strong>MCP 工具数量爆炸</strong>——一开 50 个 MCP server,工具 200+,LLM 选错率高;<strong>只接当前用的</strong></li><li><strong>生产 hook 没监控</strong>——某 hook 跑 30 秒每条 prompt 都拖,体验崩</li><li><strong>设计时没区分&quot;给个人 vs 给团队&quot;</strong>——个人偏好进了团队配置 / 团队规范进了个人配置,体验不一致</li></ol><hr><p>下一篇:<code>29-Agent设计模式.md</code>,从单 Agent / 多 Agent / 编排 / 路由 几个经典模式讲起,落到 Claude 生态怎么选型(Agent SDK 裸用 / Claude Code / 其他 Anthropic 工具)。</p>`,95)])])}const c=s(l,[["render",e]]);export{h as __pageData,c as default};
